package com.facilcomanda.orderservice.entity; import jakarta.persistence.*; import java.math.BigDecimal; @Entity @Table(name="order_items", indexes=@Index(name="idx_order_item_org", columnList="organization_id")) public class OrderItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="organization_id") private Long organizationId; @ManyToOne @JoinColumn(name="order_id") private Order order; @Column(name="product_id") private Long productId; private String productName; private Integer quantity; private BigDecimal subtotal; private String comments; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrganizationId(){return organizationId;} public void setOrganizationId(Long organizationId){this.organizationId=organizationId;} public Order getOrder(){return order;} public void setOrder(Order order){this.order=order;} public Long getProductId(){return productId;} public void setProductId(Long productId){this.productId=productId;} public String getProductName(){return productName;} public void setProductName(String productName){this.productName=productName;} public Integer getQuantity(){return quantity;} public void setQuantity(Integer quantity){this.quantity=quantity;} public BigDecimal getSubtotal(){return subtotal;} public void setSubtotal(BigDecimal subtotal){this.subtotal=subtotal;} public String getComments(){return comments;} public void setComments(String comments){this.comments=comments;} }
